# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.mathlib_axioms.search_mathlib","kind":"function","src_hash":"61c3cf72cf471396","in":{"base":"str"},"out":{"base":"List[MathlibEntry]"},"spec":{"lhs":"search_mathlib(pat)","rhs":"search the mathlib catalog by name pattern","over":{"base":"str"},"name":"search_mathlib_correct"},"guarantee":"search the mathlib catalog by name pattern","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.mathlib_axioms.search_mathlib_correct","statement":"Path(search_mathlib(x), search the mathlib catalog by name pattern)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"02cfdca0055ff750"}
def search_mathlib(pattern: str, max_results: int = 20) -> List[MathlibEntry]:
    """Search the Mathlib catalog by name pattern.

    Parameters
    ----------
    pattern : str
        Substring to search for in theorem names (case-insensitive).
    max_results : int
        Maximum number of results to return.

    Returns
    -------
    list of MathlibEntry
    """
    catalog = _load_catalog()
    pattern_lower = pattern.lower()
    results = []
    for name, entry in catalog.items():
        if pattern_lower in name.lower():
            results.append(entry)
            if len(results) >= max_results:
                break
    return results


